package com.example.eventstreamingplatform.service;

import com.example.eventstreamingplatform.model.EventMessage;
import org.springframework.kafka.core.KafkaTemplate;
import org.springframework.stereotype.Service;

@Service
public class EventProducerService {

    private final KafkaTemplate<String, EventMessage> kafkaTemplate;

    public EventProducerService(KafkaTemplate<String, EventMessage> kafkaTemplate) {
        this.kafkaTemplate = kafkaTemplate;
    }

    public void publishEvent(EventMessage eventMessage) {
        kafkaTemplate.send("events-topic", eventMessage.getEventId(), eventMessage);
    }
}

package com.example.eventstreamingplatform.service;

import com.example.eventstreamingplatform.model.EventMessage;
import org.springframework.kafka.annotation.KafkaListener;
import org.springframework.stereotype.Service;

@Service
public class EventConsumerService {

    @KafkaListener(topics = "events-topic", groupId = "event-streaming-group")
    public void consumeEvent(EventMessage eventMessage) {
        System.out.println("Consumed event: " + eventMessage.getEventId()
                + " type=" + eventMessage.getEventType()
                + " payload=" + eventMessage.getPayload()
                + " timestamp=" + eventMessage.getTimestamp());
    }
}

package com.example.eventstreamingplatform.controller;

import com.example.eventstreamingplatform.model.EventMessage;
import com.example.eventstreamingplatform.service.EventProducerService;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;

import java.time.Instant;
import java.util.UUID;

@RestController
@RequestMapping("/events")
public class EventController {

    private final EventProducerService eventProducerService;

    public EventController(EventProducerService eventProducerService) {
        this.eventProducerService = eventProducerService;
    }

    @PostMapping
    public ResponseEntity<EventMessage> publishEvent(@RequestBody EventMessage request) {
        EventMessage event = new EventMessage(
                request.getEventId() != null ? request.getEventId() : UUID.randomUUID().toString(),
                request.getEventType(),
                request.getPayload(),
                request.getTimestamp() > 0 ? request.getTimestamp() : Instant.now().toEpochMilli()
        );
        eventProducerService.publishEvent(event);
        return ResponseEntity.accepted().body(event);
    }
}

